import React, { useState, useEffect, useCallback } from "react";
import axios from "axios";
import ReactDOM from 'react-dom/client';
import { useSelector } from "react-redux";
import InternshipCard from "../components/InternshipCard";
import InternshipModal from "../components/InternshipModal";
import "./Internship.css"; // Optional: if you use custom styles

const Internship = () => {
  const user = useSelector((state) => state.user);
  const userRole = user?.role;
  const token = user?.token;

  const [internships, setInternships] = useState([]);
  const [applications, setApplications] = useState([]);
  const [selectedInternship, setSelectedInternship] = useState(null);
  const [showModal, setShowModal] = useState(false);

  // ✅ Fetch internships — no dependency on props/state
  const fetchInternships = useCallback(async () => {
    try {
      const response = await axios.get("/api/internships");
      setInternships(response.data);
    } catch (error) {
      console.error("Failed to fetch internships:", error);
    }
  }, []);

  // ✅ Fetch applications — depends on token
  const fetchApplications = useCallback(async () => {
    if (!token) return;
    try {
      const response = await axios.get("/api/applications", {
        headers: { Authorization: `Bearer ${token}` },
      });
      setApplications(response.data);
    } catch (error) {
      console.error("Failed to fetch applications:", error);
    }
  }, [token]);

  // ✅ useEffect uses stable callbacks
  useEffect(() => {
    fetchInternships();
    if (userRole === "Student") {
      fetchApplications();
    }
  }, [fetchInternships, fetchApplications, userRole]);

  // 🔘 Handle Apply
  const handleApply = async (internshipId) => {
    try {
      const response = await axios.post(
        "/api/applications",
        { internshipId },
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );
      setApplications([...applications, response.data]);
      alert("Applied successfully!");
    } catch (error) {
      console.error("Failed to apply:", error);
      alert("Application failed");
    }
  };

  // 🔘 Handle Edit
  const handleEdit = (internship) => {
    setSelectedInternship(internship);
    setShowModal(true);
  };

  // 🔘 Handle Delete
  const handleDelete = async (internshipId) => {
    if (!window.confirm("Are you sure you want to delete this internship?")) return;

    try {
      await axios.delete(`/api/internships/${internshipId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setInternships(internships.filter((i) => i._id !== internshipId));
    } catch (error) {
      console.error("Failed to delete internship:", error);
      alert("Delete failed");
    }
  };

  // 🔘 Handle Save from Modal (add or update)
  const handleSave = async (internshipData) => {
    try {
      if (selectedInternship) {
        // Update
        const response = await axios.put(
          `/api/internships/${selectedInternship._id}`,
          internshipData,
          {
            headers: { Authorization: `Bearer ${token}` },
          }
        );
        setInternships(
          internships.map((i) =>
            i._id === selectedInternship._id ? response.data : i
          )
        );
      } else {
        // Add
        const response = await axios.post("/api/internships", internshipData, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setInternships([...internships, response.data]);
      }
      setShowModal(false);
      setSelectedInternship(null);
    } catch (error) {
      console.error("Failed to save internship:", error);
      alert("Save failed");
    }
  };

  return (
    <div className="internship-page">
      <div className="internship-header">
        <h1>Internship Opportunities</h1>
        {(userRole === "Admin" || userRole === "HR") && (
          <button onClick={() => setShowModal(true)} className="add-button">
            + Add Internship
          </button>
        )}
      </div>

      <div className="internship-list">
        {internships.length === 0 ? (
          <p>No internships available.</p>
        ) : (
          internships.map((internship) => {
            const hasApplied = applications.some(
              (app) => app.internshipId === internship._id
            );

            return (
              <InternshipCard
                key={internship._id}
                internship={internship}
                userRole={userRole}
                onApply={() => handleApply(internship._id)}
                onEdit={() => handleEdit(internship)}
                onDelete={() => handleDelete(internship._id)}
                hasApplied={hasApplied}
              />
            );
          })
        )}
      </div>

      {showModal && (
        <InternshipModal
          internship={selectedInternship}
          onClose={() => {
            setShowModal(false);
            setSelectedInternship(null);
          }}
          onSave={handleSave}
        />
      )}
    </div>
  );
};

export default Internship;
